// Solution
function solve(html) {
  let stack = [];
  let currentLevel = 0;
  for (let i = 0; i < html.length; i++) {
    if (html[i] === '<' && html[i + 1] === 'h') {
      let level = parseInt(html.slice(i + 2, i + 2 + 1));
      if (level >= 1 && level <= 6) {
        if (currentLevel === 0) {
          stack.push(level);
        } else if (currentLevel < level) {
          stack.push(level);
        } else {
          return false;
        }
        currentLevel = level;
      }
    } else if (html[i] === '>') {
      if (currentLevel > 0) {
        stack.pop();
        currentLevel -= 1;
      }
    }
  }
  return stack.length === 0;
}

